fn main() {
    let args: Vec<String> = std::env::args().collect();
    let mut table: Option<String> = None;
    let mut output: Option<String> = None;

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--table" if i + 1 < args.len() => {
                table = Some(args[i + 1].clone());
                i += 2;
            }
            "--output" if i + 1 < args.len() => {
                output = Some(args[i + 1].clone());
                i += 2;
            }
            _ => i += 1,
        }
    }

    let table = match table {
        Some(t) => t,
        None => {
            print_usage();
            exit(1);
        }
    };
    let output = output.unwrap_or_else(|| format!("{}.csv", table));

    match export_table(&table, &output) {
        Ok(count) => println!("Exported {} record(s) from '{}' to {}", count, table, output),
        Err(e) => {
            eprintln!("Error exporting '{}': {}", table, e);
            exit(1);
        }
    }
}

