/// Generic exporter: read the type's columns for the header, select every row,
/// and write a CSV in column order.
fn export_object<T: DomainObject + Default>(output: &str) -> Result<usize, String> {
    let mut probe = T::default();
    probe.initialize();
    let qualified = probe.base().table_name.clone();
    let columns: Vec<&'static str> = T::columns().iter().map(|c| c.name).collect();

    let rows = DBPersist::select(&format!("SELECT * FROM {}", qualified), "default")
        .map_err(|e| e.to_string())?;

    let mut writer = csv::Writer::from_path(output).map_err(|e| e.to_string())?;
    writer.write_record(&columns).map_err(|e| e.to_string())?;
    for row in &rows {
        let fields: Vec<String> = columns.iter().map(|c| cell_to_string(row.get(*c))).collect();
        writer.write_record(&fields).map_err(|e| e.to_string())?;
    }
    writer.flush().map_err(|e| e.to_string())?;
    Ok(rows.len())
}

fn cell_to_string(v: Option<&Value>) -> String {
    match v {
        None | Some(Value::Null) => String::new(),
        Some(Value::String(s)) => s.clone(),
        Some(Value::Bool(b)) => b.to_string(),
        Some(other) => other.to_string(),
    }
}
